ClinicalImpression|http://hl7.org/fhir/StructureDefinition/ClinicalImpression"]}]}, {:id=>"Composition.section:sectionPastProblems", :short=>"Patient Summary History of Past Illness Section", :definition=>"Information about a patient's conditions that were suffered in the past and are no longer tracked in the Problem List.", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"11348-0", :entries=>[{:id=>"Composition.section:sectionPastProblems.entry:pastProblem", :min=>0, :max=>"*", :required=>false, :mustSupport=>false, :profiles=>["Condition|http://hl7.org.au/fhir/ps/StructureDefinition/au-ps-condition"]}]}, {:id=>"Composition.section:sectionPregnancyHx", :short=>"Patient Summary History of Pregnancy Section", :definition=>"Information about whether a patient is currently pregnant or not and can contain additional summarising information about the outcome of earlier pregnancies.", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"10162-6", :entries=>[{:id=>"Composition.section:sectionPregnancyHx.entry:pregnancyStatus", :min=>0, :max=>"*", :required=>false, :mustSupport=>false, :profiles=>["Observation|http://hl7.org/fhir/uv/ips/StructureDefinition/Observation-pregnancy-status-uv-ips"]}, {:id=>"Composition.section:sectionPregnancyHx.entry:pregnancyOutcome", :min=>0, :max=>"*", :required=>false, :mustSupport=>false, :profiles=>["Observation|http://hl7.org/fhir/uv/ips/StructureDefinition/Observation-pregnancy-outcome-uv-ips"]}]}, {:id=>"Composition.section:sectionPatientStory", :short=>"Patient Summary Patient Story Section", :definition=>"Information about what matters to a patient. This can include needs, strengths, values, concerns and preferences to others providing support and care. The patient's story, provided here, can be told by the patient or by a proxy.", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"81338-6", :entries=>[]}, {:id=>"Composition.section:sectionPlanOfCare", :short=>"Patient Summary Plan of Care Section", :definition=>"Information about a patient's plans of care containing the expectations for care including proposals, goals, and order requests for monitoring, tracking, or improving the condition of the patient.", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"18776-5", :entries=>[{:id=>"Composition.section:sectionPlanOfCare.entry:carePlan", :min=>0, :max=>"*", :required=>false, :mustSupport=>false, :profiles=>["CarePlan|http://hl7.org/fhir/StructureDefinition/CarePlan"]}, {:id=>"Composition.section:sectionPlanOfCare.entry:immunizationRecommendation", :min=>0, :max=>"*", :required=>false, :mustSupport=>false, :profiles=>["ImmunizationRecommendation|http://hl7.org/fhir/StructureDefinition/ImmunizationRecommendation"]}]}, {:id=>"Composition.section:sectionSocialHistory", :short=>"Patient Summary Social History Section", :definition=>"Information about a patient's health related \"lifestyle factors\" or \"lifestyle observations\" (e.g. smoke habits, alcohol consumption, diets, risky habits).", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"29762-2", :entries=>[{:id=>"Composition.section:sectionSocialHistory.entry:smokingTobaccoUse", :min=>0, :max=>"1", :required=>false, :mustSupport=>false, :profiles=>["Observation|http://hl7.org.au/fhir/ps/StructureDefinition/au-ps-smokingstatus"]}, {:id=>"Composition.section:sectionSocialHistory.entry:alcoholUse", :min=>0, :max=>"1", :required=>false, :mustSupport=>false, :profiles=>["Observation|http://hl7.org/fhir/uv/ips/StructureDefinition/Observation-alcoholuse-uv-ips"]}]}, {:id=>"Composition.section:sectionVitalSigns", :short=>"Patient Summary Vital Signs Section", :definition=>"Information about a patient's vital signs including blood pressure, body temperature, heart rate, and respiratory rate. It can also include other clinical findings, such as height, weight, body mass index, head circumference, and pulse oximetry. In particular, notable vital signs or physical findings such as the most recent, maximum and/or minimum, baseline, or relevant trends can be included.", :min=>0, :max=>"1", :required=>false, :mustSupport=>true, :code=>"8716-3", :entries=>[{:id=>"Composition.section:sectionVitalSigns.entry:vitalSign", :min=>0, :max=>"*", :required=>false, :mustSupport=>false, :profiles=>["Observation|http://hl7.org/fhir/StructureDefinition/vitalsigns"]}]}], [{:expression=>"author", :label=>"author"}, {:expression=>"date", :label=>"date"}, {:expression=>"section", :label=>"section"}, {:expression=>"status", :label=>"status"}, {:expression=>"subject", :label=>"subject"}, {:expression=>"title", :label=>"title"}, {:expression=>"type", :label=>"type"}])
